// // This module implements a 8-bit AND gate with disable functionality. When the enable signal (EN) is high, the module outputs the bitwise AND of inputs A and B. If EN is low, the output will be set to one, effectively enabling the AND operation.
module top_module(
    OUT,
    A,
    B,
    EN
);output reg [7:0] OUT;
    input [7:0] A;
    input [7:0] B;
    input EN;

    always @(*) begin
        if (EN) begin
            OUT = A ^ B;
        end
        else begin
            OUT = 8'b0;
        end
    end

endmodule
